// ── Universal Game Coordinate ───────────────────────────────────────

/**
 * Universal Game Coordinate — deterministically addresses any game state.
 *
 * Inspired by the storms-watch / stars.fish universal atlas tuple.
 * Given a GameCoordinate, the exact game state (map, entities, encounters)
 * can be recreated from scratch. The coordinate formalizes the save.
 *
 * Uses cube coordinates (q + r + s = 0) for the hex grid.
 * Time is gnosis time (picolorenzos), not human time.
 * Floating-point precision is acceptable.
 */
export interface GameCoordinate {
  /** Universe seed. Deterministic procedural generation. */
  readonly seed: number;
  /** Gnostic dimension (0-9) or void dimension (10-12) */
  readonly dimension: DimensionIndex;
  /** Hex cube coordinate Q */
  readonly hexQ: number;
  /** Hex cube coordinate R */
  readonly hexR: number;
  /** Hex cube coordinate S (constrained: q + r + s = 0) */
  readonly hexS: number;
  /** Game time in picolorenzos. Gnosis time, not human time. */
  readonly tick: number;
}

// ── Gnosis Time in The Void ─────────────────────────────────────────

/**
 * Time dilation per dimension.
 *
 * Time moves differently in each dimension, on a gnostic scale:
 * - Dimension 0 (Bythos): no time exists (dilation = 0)
 * - Dimension 1 (Barbelo): time is barely perceptible (1 pLo per game tick)
 * - Dimension 3 (Proton): normal time (3 pLo per game tick — the comfortable zone)
 * - Dimension 5 (Emanations): time becomes visible and navigable (6 pLo per tick)
 * - Dimension 9 (Pleroma): time is overwhelming (55 pLo per tick)
 * - Void dimensions: time is alien (fractional / negative / parallel)
 *
 * The dilation rate equals β₁ — the gnostic number for that dimension.
 * This means one game action in Pleroma advances 55 pLo, while the same
 * action in Proton advances only 3 pLo. Higher dimensions move faster.
 */
export const DIMENSION_TIME_DILATION: Record<DimensionIndex, number> = {
  0: 0,       // Bythos: timeless
  1: 1,       // Barbelo: minimal
  2: 2,       // Syzygy: paired
  3: 3,       // Proton: comfortable
  4: 5,       // Primitives: deepening
  5: 6,       // Emanations: visible time
  6: 9,       // Sophia: compressed
  7: 10,      // Kenoma: stretched
  8: 21,      // Void: fractured
  9: 55,      // Pleroma: total
  10: -1,     // Cross-File: retrograde
  11: 0.618,  // Temporal: φ⁻¹ (golden ratio inverse)
  12: Math.PI, // Data-Plane: irrational
} as const;

/**
 * Game time state — tracks time in gnosis units.
 * Aeons, pleromas, kenomas, sophias, barbelos.
 */
export interface VoidGameTime {
  /** Total elapsed picolorenzos in this game session */
  readonly totalPicolorenzos: number;
  /** Decomposed gnosis time (for display) */
  readonly gnosticTimestamp: GnosticTimestamp;
  /** Current dimension's time dilation rate */
  readonly dilationRate: number;
}

// ── Rarity System ───────────────────────────────────────────────────

/**
 * Rarity tiers derived from gnostic β₁ values.
 * Drop probability = 1 / β₁(dimension).
 * Math-based, provably rare, ZK-verified.
 */
export type RarityTier =
  | 'common'
  | 'uncommon'
  | 'rare'
  | 'epic'
  | 'legendary'
  | 'mythic'
  | 'cosmic'
  | 'void_unique';

export interface RarityDefinition {
  readonly tier: RarityTier;
  readonly sourceDimension: DimensionIndex;
  /** β₁ value — reciprocal is the drop rate */
  readonly beta1: number;
  /** Approximate drop rate = 1/β₁ */
  readonly dropRate: number;
}

export const RARITY_TIERS: readonly RarityDefinition[] = [
  { tier: 'common', sourceDimension: 3, beta1: 3, dropRate: 1 / 3 },
  { tier: 'uncommon', sourceDimension: 4, beta1: 5, dropRate: 1 / 5 },
  { tier: 'rare', sourceDimension: 5, beta1: 6, dropRate: 1 / 6 },
  { tier: 'epic', sourceDimension: 6, beta1: 9, dropRate: 1 / 9 },
  { tier: 'legendary', sourceDimension: 7, beta1: 10, dropRate: 1 / 10 },
  { tier: 'mythic', sourceDimension: 8, beta1: 21, dropRate: 1 / 21 },
  { tier: 'cosmic', sourceDimension: 9, beta1: 55, dropRate: 1 / 55 },
  { tier: 'void_unique', sourceDimension: 10, beta1: Infinity, dropRate: 0 },
] as const;

// ── Player System ───────────────────────────────────────────────────

/** The 7 Phyles — philosophical particleTypes */
export type PhyleName =
  | 'philosopher'
  | 'nihilist'
  | 'aesthete'
  | 'builder'
  | 'hedonist'
  | 'scientist'
  | 'mystic';

/** The 4 fundamental particle types (Combat Archetypes) */
export type ParticleType = 'fermion' | 'boson' | 'anyon' | 'tachyon';

/** God Formula phases — mapped to every game action */
export type GodFormulaPhase = 'fork' | 'race' | 'fold' | 'vent';

/**
 * Observer state — the player in The Void.
 * Governed by buleyean RL: failure is the survival resource.
 */
export interface ObserverState {
  /** Observer identity (DID from Nexus) */
  readonly did: string;
  /** Current position in the universe */
  readonly coordinate: GameCoordinate;
  /** Energy pool (formerly HEX) — movement currency. Zero = teleport to real life. */
  energy: number;
  /** Major Phyle */
  readonly majorPhyle: PhyleName;
  /** Minor Phyle (must differ from major) */
  readonly minorPhyle: PhyleName;
  /** Particle Type (Combat particleType) */
  readonly particleType: ParticleType;
  /** Total failures accumulated (learning resource — the higher the better) */
  totalFailures: number;
  /** Total successes (nice but insufficient) */
  totalSuccesses: number;
  /** Learning energy — generated by failure, drained by stagnation */
  wisdom: number;
  /** Destructive action parameter (selfish entropy generation) */
  sin: number;
  /** Picolorenzos since last new failure (stagnation counter — gnosis time) */
  ploSinceLastFailure: number;
  /** Current gnostic level achieved */
  highestDimension: DimensionIndex;
  /** Cycle count — how many times the Quine has completed */
  cycleCount: number;
  /** Sliver — the +1 carried forward from each cycle */
  sliver: number;
  /** If the observer is currently trapped inside a nexus knot */
  activeKnotEncounter: KnotEncounterState | null;
  /** 
   * True if the observer reached Pleroma (folded the universe) without accruing any sin.
   * "If you beat the game without conflict, you are an Angel."
   * Renders as a pristine 'Halogram' rather than a standard 'Hologram'.
   */
  isAngel?: boolean;
}

// ── Boss Encounter State ────────────────────────────────────────────

export interface KnotEncounterState {
  readonly knotId: string;
  readonly dimension: DimensionIndex;
  /** The Phyle that owns this Nexus (dynamic target) */
  readonly targetPhyle: PhyleName;
  /** How rich/popular this Phyle is (multiplies ICE complexity and payout) */
  readonly phylePopularity: number;
  /** The remaining Topological Knot complexity (ICE HP) */
  readonly knotComplexity: number;
  /** The maximum Topological Knot complexity */
  readonly maxKnotComplexity: number;
  /** The current intensity of the systemic entropy (zombie waves) */
  readonly systemicEntropy: number;
  /** How many ticks this encounter has lasted (scales entropy spike) */
  readonly ticksElapsed: number;
  /** Number of observers sharing the load (scales knot solving, splits entropy) */
  readonly participants: number;
}

